 4→async function runLogout(): Promise<void> {
 5→	const write = (msg: string) => process.stdout.write(`${msg}\n`);
 6→
 7→	const credentials = loadCredentials();
 8→	if (!credentials) {
 9→		write("Not logged in.");
10→		return;
11→	}
12→
13→	clearCredentials();
14→	write("Logged out successfully.");
15→}
