 11→function getCliParams(): { cliCallback: string; state: string } | null {
 12→	const params = new URLSearchParams(window.location.search);
 13→	const cliCallback = params.get("cli_callback");
 14→	const state = params.get("state");
 15→	if (!cliCallback || !state) return null;
 16→	try {
 17→		const url = new URL(cliCallback);
 18→		if (url.hostname !== "127.0.0.1") return null;
 19→	} catch {
 20→		return null;
 21→	}
 22→	return { cliCallback, state };
 23→}
